import{_ as e,o as t,c as l,a2 as i}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"每日产品或功能拆解","description":"","frontmatter":{},"headers":[],"relativePath":"02-product/daily/README.md","filePath":"02-product/daily/README.md","lastUpdated":1784212366000}'),s={name:"02-product/daily/README.md"};function n(r,a,o,d,p,c){return t(),l("div",null,[...a[0]||(a[0]=[i(`<h1 id="每日产品或功能拆解" tabindex="-1">每日产品或功能拆解 <a class="header-anchor" href="#每日产品或功能拆解" aria-label="Permalink to &quot;每日产品或功能拆解&quot;">​</a></h1><p>每天选择一个产品中的一个具体功能或任务，完成一次小型产品分析。不要泛泛分析整个产品，也不要把界面截图当成拆解结论。</p><h2 id="观察路径" tabindex="-1">观察路径 <a class="header-anchor" href="#观察路径" aria-label="Permalink to &quot;观察路径&quot;">​</a></h2><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>目标用户与场景 → 当前问题与替代方案 → 功能方案与流程</span></span>
<span class="line"><span>→ 用户价值 → 产品目标与指标 → 商业/技术成本 → 风险与改进</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>证据可以来自真实使用、官方文档、定价页、更新日志、公开 Issue、产品评论、状态页、公开数据和竞品对比。始终标记事实、推断与个人观点。</p><h2 id="记录方式" tabindex="-1">记录方式 <a class="header-anchor" href="#记录方式" aria-label="Permalink to &quot;记录方式&quot;">​</a></h2><ol><li>复制 <a href="./_template">_template.md</a>。</li><li>按 <code>YYYY/MM/YYYY-MM-DD-product-feature.md</code> 保存。</li><li>同一产品可以多次出现，但每次只分析一个任务、功能或决策。</li><li>每七次拆解做一次横向总结，提炼可迁移的产品模式。</li></ol><h2 id="完成标准" tabindex="-1">完成标准 <a class="header-anchor" href="#完成标准" aria-label="Permalink to &quot;完成标准&quot;">​</a></h2><ul><li>[ ] 说明用户、场景、任务和现有替代方案。</li><li>[ ] 至少使用一个带日期和链接的外部证据或真实使用记录。</li><li>[ ] 分析价值、指标、成本和取舍，不只描述功能。</li><li>[ ] 给出一个保留、一个删除或一个改进建议及其风险。</li></ul>`,9)])])}const m=e(s,[["render",n]]);export{u as __pageData,m as default};
